parameters.jsCode:
let totalPortfolioValue = 0;
const output = [];
for (const item of $input.all()) {
    totalPortfolioValue += item.json.Value || 0;
  output.push({
    "Asset": item.json.Asset,
    "Amount": item.json.Amount,
    "Price": item.json.Price,
    "Value": item.json.Value
  })
}

return {
    output,
    totalPortfolioValue
  }

